// ===========================================================================
// AppHost.tsx — Executa o source de um artifact React e renderiza o resultado.
//
// Pipeline:
//   source -> compile() -> new Function(scope, code) -> App component
//   -> React.createElement(App) -> dentro de ErrorBoundary
//
// Princípio: chat NUNCA pode dar pau. Qualquer erro de compile, runtime
// ou render é capturado e renderizado como fallback inline.
// ===========================================================================

import * as React from "react"
import { compile, CompileError } from "./compile.js"
import { buildScope, type AppActions } from "./runtime.js"

export interface AppHostProps {
  /** Source TSX single-file. Espera um `function App() {...}`. */
  source: string
  actions: AppActions
  messages?: Partial<{
    errorTitle: string
    errorTranspile: string
    errorRuntime: string
    errorBlocked: string
  }>
}

interface CompileFailure {
  stage: "transpile" | "validate" | "execute" | "no-component"
  message: string
  detail?: string
}

interface CompiledOk {
  Component: React.ComponentType
}

function compileSource(
  source: string,
  scope: Record<string, unknown>,
): CompiledOk | CompileFailure {
  let compiled: { code: string }
  try {
    compiled = compile(source, "App.tsx")
  } catch (err) {
    if (err instanceof CompileError) {
      return {
        stage: err.stage,
        message: err.message,
        detail: err.violations?.join(", "),
      }
    }
    return {
      stage: "transpile",
      message: err instanceof Error ? err.message : String(err),
    }
  }

  const wrapped = `${compiled.code}\n;return (typeof App !== 'undefined' ? App : null);`

  let Component: unknown
  try {
    const scopeKeys = Object.keys(scope)
    const scopeVals = scopeKeys.map((k) => scope[k])
    const factory = new Function(...scopeKeys, wrapped)
    Component = factory(...scopeVals)
  } catch (err) {
    return {
      stage: "execute",
      message: err instanceof Error ? err.message : String(err),
    }
  }

  if (typeof Component !== "function") {
    return {
      stage: "no-component",
      message: `Source did not define an "App" function`,
    }
  }

  return { Component: Component as React.ComponentType }
}

class RuntimeErrorBoundary extends React.Component<
  { children: React.ReactNode; onError: (err: Error) => void },
  { err: Error | null }
> {
  override state: { err: Error | null } = { err: null }
  static getDerivedStateFromError(err: Error) {
    return { err }
  }
  override componentDidCatch(err: Error) {
    this.props.onError(err)
  }
  override render() {
    if (this.state.err) return null
    return this.props.children
  }
}

export function AppHost({ source, actions, messages }: AppHostProps) {
  const scope = React.useMemo(() => buildScope({ actions }), [actions])
  const compiled = React.useMemo(() => compileSource(source, scope), [source, scope])
  const [runtimeError, setRuntimeError] = React.useState<Error | null>(null)

  React.useEffect(() => {
    setRuntimeError(null)
  }, [source])

  if ("stage" in compiled) {
    return <Fallback failure={compiled} messages={messages} />
  }

  if (runtimeError) {
    return (
      <Fallback
        failure={{ stage: "execute", message: runtimeError.message }}
        messages={messages}
      />
    )
  }

  const Component = compiled.Component
  return (
    <RuntimeErrorBoundary onError={setRuntimeError}>
      <Component />
    </RuntimeErrorBoundary>
  )
}

function Fallback({
  failure,
  messages,
}: {
  failure: CompileFailure
  messages?: AppHostProps["messages"]
}) {
  const m = messages ?? {}
  const title = m.errorTitle ?? "Não foi possível renderizar este bloco."
  const label =
    failure.stage === "validate"
      ? m.errorBlocked ?? "Construção bloqueada"
      : failure.stage === "execute"
        ? m.errorRuntime ?? "Erro em tempo de execução"
        : m.errorTranspile ?? "Erro ao compilar"
  return (
    <div className="border border-destructive/30 bg-destructive/5 text-destructive-foreground rounded-md p-3 text-sm">
      <div className="font-medium">{title}</div>
      <div className="text-xs opacity-80 mt-1">
        {label}: {failure.message}
        {failure.detail ? <> ({failure.detail})</> : null}
      </div>
    </div>
  )
}

// ===========================================================================
// compile.ts — Transpile JSX → JS e valida ausência de constructs proibidos.
//
// Estratégia:
// 1. transpile JSX/TS → JS via sucrase (sem typecheck)
// 2. valida o JS resultante com regex em palavras-fronteira
//
// Regex é suficiente porque o escopo de execução também não expõe nenhum
// dos identifiers proibidos — o validator é defesa-em-profundidade, não
// fronteira de segurança. A fronteira é o `scope` do `new Function`.
// ===========================================================================

import { transform } from "sucrase"

// Construções proibidas no código de artifact React. A "verdade" semântica
// fica no skill body do SDK (que ensina o agente); este array é a defesa
// em profundidade do cliente — espelha-o conceitualmente, mas o cliente
// é a única fronteira que importa pra segurança.
const FORBIDDEN_CONSTRUCTS = [
  { name: "while", description: "while loops (incluindo while(true))" },
  { name: "for", description: "for loops sem bound estático" },
  { name: "do", description: "do/while loops" },
  { name: "setInterval", description: "Timers periódicos" },
  { name: "setTimeout", description: "Timers" },
  { name: "eval", description: "Avaliação dinâmica de código" },
  { name: "Function", description: "new Function(...) constructor" },
  { name: "Worker", description: "Web Workers" },
  { name: "fetch", description: "fetch direto (artifacts são self-contained)" },
  { name: "XMLHttpRequest", description: "Requisições HTTP diretas" },
  { name: "document", description: "Acesso direto ao DOM" },
  { name: "window", description: "Acesso direto a window globals" },
  { name: "localStorage", description: "Storage do browser" },
  { name: "sessionStorage", description: "Storage do browser" },
  { name: "import", description: "Imports dinâmicos" },
  { name: "require", description: "CommonJS imports" },
] as const

export interface CompileResult {
  /** JS final — wrappable em `new Function("scope", code)`. */
  code: string
  /** Avisos não fatais (ex: identificador suspeito mas em string). */
  warnings: string[]
}

export class CompileError extends Error {
  readonly stage: "transpile" | "validate"
  readonly violations?: string[]
  constructor(message: string, stage: "transpile" | "validate", violations?: string[]) {
    super(message)
    this.name = "CompileError"
    this.stage = stage
    this.violations = violations
  }
}

const FORBIDDEN_PATTERNS = FORBIDDEN_CONSTRUCTS.map((c) => ({
  name: c.name,
  description: c.description,
  // \b{name}\b — palavra inteira; escape pra .
  re: new RegExp(`\\b${c.name.replace(/[-/\\^$*+?.()|[\]{}]/g, "\\$&")}\\b`),
}))

/**
 * Compila um arquivo TSX/JSX para JS executável.
 *
 * @param source código-fonte (TSX, JSX ou JS)
 * @param filename nome para mensagens de erro (não é caminho real)
 */
export function compile(source: string, filename = "App.tsx"): CompileResult {
  let transpiled: string
  try {
    const out = transform(source, {
      transforms: ["typescript", "jsx"],
      jsxRuntime: "classic",
      production: true,
      filePath: filename,
    })
    transpiled = out.code
  } catch (err) {
    throw new CompileError(
      `Falha ao transpilar ${filename}: ${err instanceof Error ? err.message : String(err)}`,
      "transpile",
    )
  }

  const violations = validate(transpiled)
  if (violations.length > 0) {
    throw new CompileError(
      `Construções proibidas em ${filename}: ${violations.join(", ")}`,
      "validate",
      violations,
    )
  }

  return { code: transpiled, warnings: [] }
}

/** Procura identificadores proibidos no código transpilado. */
export function validate(code: string): string[] {
  // Remove comments e strings pra reduzir falsos positivos. Conservador:
  // strings entre aspas duplas/simples/template; comments // e /* */.
  const stripped = stripStringsAndComments(code)
  const found: string[] = []
  for (const { name, re } of FORBIDDEN_PATTERNS) {
    if (re.test(stripped)) found.push(name)
  }
  return found
}

function stripStringsAndComments(src: string): string {
  let out = ""
  let i = 0
  const n = src.length
  while (i < n) {
    const ch = src[i]!
    const next = src[i + 1]
    // line comment
    if (ch === "/" && next === "/") {
      while (i < n && src[i] !== "\n") i++
      continue
    }
    // block comment
    if (ch === "/" && next === "*") {
      i += 2
      while (i < n && !(src[i] === "*" && src[i + 1] === "/")) i++
      i += 2
      continue
    }
    // single/double/template string
    if (ch === '"' || ch === "'" || ch === "`") {
      const quote = ch
      i++
      while (i < n) {
        const c = src[i]!
        if (c === "\\") {
          i += 2
          continue
        }
        if (c === quote) {
          i++
          break
        }
        i++
      }
      continue
    }
    out += ch
    i++
  }
  return out
}

// ===========================================================================
// runtime.ts — Constrói o scope passado ao `new Function` em AppHost.
//
// O scope é o conjunto fechado de identificadores que o código gerado pelo
// agente pode usar. Tudo fora daqui não está acessível (defesa-em-profundidade
// junto com o validator de compile.ts).
// ===========================================================================

import * as React from "react"
import * as Recharts from "recharts"
import * as FramerMotion from "framer-motion"
import * as LucideIcons from "lucide-react"

import { Card, CardHeader, CardTitle, CardDescription, CardContent, CardFooter } from "../ui/card.js"
import { Button } from "../ui/button.js"
import { Badge } from "../ui/badge.js"
import { Progress } from "../ui/progress.js"
import { Separator } from "../ui/separator.js"
import { Skeleton } from "../ui/skeleton.js"
import { ScrollArea } from "../ui/scroll-area.js"
import { Input } from "../ui/input.js"
import { Tooltip, TooltipTrigger, TooltipContent, TooltipProvider } from "../ui/tooltip.js"
import {
  Sheet,
  SheetTrigger,
  SheetContent,
  SheetHeader,
  SheetTitle,
} from "../ui/sheet.js"
import {
  Dialog,
  DialogTrigger,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from "../ui/dialog.js"
import { Alert, AlertTitle, AlertDescription } from "../ui/alert.js"
import {
  Collapsible,
  CollapsibleTrigger,
  CollapsibleContent,
} from "../ui/collapsible.js"

export interface AppActions {
  /** Envia `text` como nova mensagem do usuário pro agente. */
  ask: (text: string) => void
}

export interface BuildScopeOptions {
  actions: AppActions
}

// ─── Shims pra componentes ainda não presentes em src/ui ────────────────────
// Estratégia: render children num <div> simples; o agente pode usar mas o
// look-and-feel cai pro padrão. Quando trazermos os shadcn reais, basta
// substituir o import.

type DivProps = React.HTMLAttributes<HTMLDivElement>
const passthrough = (name: string) =>
  function Shim(props: DivProps) {
    return React.createElement("div", { "data-shim": name, ...props })
  }

const Tabs = passthrough("Tabs")
const TabsList = passthrough("TabsList")
const TabsTrigger = passthrough("TabsTrigger")
const TabsContent = passthrough("TabsContent")
const Slider = passthrough("Slider")
const Switch = passthrough("Switch")
const Avatar = passthrough("Avatar")
const AvatarImage = passthrough("AvatarImage")
const AvatarFallback = passthrough("AvatarFallback")
const Select = passthrough("Select")
const SelectTrigger = passthrough("SelectTrigger")
const SelectValue = passthrough("SelectValue")
const SelectContent = passthrough("SelectContent")
const SelectItem = passthrough("SelectItem")
const Toggle = passthrough("Toggle")

// ─── Builder ────────────────────────────────────────────────────────────────

export function buildScope(opts: BuildScopeOptions): Record<string, unknown> {
  const icon = (name: string) => {
    const Comp = (LucideIcons as Record<string, unknown>)[name]
    return typeof Comp === "function" ? Comp : null
  }

  return {
    // React essencial
    React,
    useState: React.useState,
    useMemo: React.useMemo,
    useCallback: React.useCallback,
    useEffect: React.useEffect,
    Fragment: React.Fragment,

    // shadcn UI
    Card,
    CardHeader,
    CardTitle,
    CardDescription,
    CardContent,
    CardFooter,
    Button,
    Badge,
    Progress,
    Separator,
    Skeleton,
    ScrollArea,
    Input,
    Tooltip,
    TooltipTrigger,
    TooltipContent,
    TooltipProvider,
    Sheet,
    SheetTrigger,
    SheetContent,
    SheetHeader,
    SheetTitle,
    Dialog,
    DialogTrigger,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogDescription,
    Alert,
    AlertTitle,
    AlertDescription,
    Collapsible,
    CollapsibleTrigger,
    CollapsibleContent,
    // shims (ainda sem shadcn instalado)
    Tabs,
    TabsList,
    TabsTrigger,
    TabsContent,
    Slider,
    Switch,
    Avatar,
    AvatarImage,
    AvatarFallback,
    Select,
    SelectTrigger,
    SelectValue,
    SelectContent,
    SelectItem,
    Toggle,

    // Charts (namespace + spread por conveniência)
    Recharts,
    ResponsiveContainer: Recharts.ResponsiveContainer,
    LineChart: Recharts.LineChart,
    BarChart: Recharts.BarChart,
    PieChart: Recharts.PieChart,
    AreaChart: Recharts.AreaChart,
    RadarChart: Recharts.RadarChart,
    XAxis: Recharts.XAxis,
    YAxis: Recharts.YAxis,
    Legend: Recharts.Legend,
    CartesianGrid: Recharts.CartesianGrid,
    Line: Recharts.Line,
    Bar: Recharts.Bar,
    Pie: Recharts.Pie,
    Area: Recharts.Area,
    Radar: Recharts.Radar,
    Cell: Recharts.Cell,

    // Motion
    motion: FramerMotion.motion,
    AnimatePresence: FramerMotion.AnimatePresence,
    MotionConfig: FramerMotion.MotionConfig,
    LayoutGroup: FramerMotion.LayoutGroup,
    Reorder: FramerMotion.Reorder,

    // Icons via helper
    icon,

    // Helpers / interaction
    __actions: opts.actions,
  }
}

import React, { useEffect, useState, useMemo } from "react";
import { MessageSquare } from "lucide-react";
import { cn } from "../lib/utils.js";
import { ChatProvider, useChatContext } from "../hooks/ChatProvider.js";
import { MessageList } from "./MessageList.js";
import { MessageInput } from "./MessageInput.js";
import { ModelSelect } from "./ModelSelect.js";
import { LocaleSelect } from "./LocaleSelect.js";
import { useModels } from "../hooks/useModels.js";
import { LocaleProvider, useTranslation, resolveLocale } from "../i18n/index.js";
import type { CustomMessages, CustomLocaleInfo } from "../i18n/index.js";
import type { Message } from "../types.js";
import type { ChatTransport } from "../transport.js";

// Literal classes so Tailwind's source scanner picks them all up at build time.
const MAX_WIDTH_CLASS = {
  sm: "max-w-sm",
  md: "max-w-md",
  lg: "max-w-lg",
  xl: "max-w-xl",
  "2xl": "max-w-2xl",
  "3xl": "max-w-3xl",
  "4xl": "max-w-4xl",
  "5xl": "max-w-5xl",
  "6xl": "max-w-6xl",
  "7xl": "max-w-7xl",
} as const;

export type ChatMaxWidth = keyof typeof MAX_WIDTH_CLASS | false;

export interface ChatProps {
  /** Base URL do servico openclaude (ex: http://localhost:9500/api/v1/ai). */
  endpoint: string;
  token?: string;
  /** Sessao live existente. Se omitida, o hook cria uma via POST /conversations. */
  sessionId?: string;
  /**
   * Agent ID enviado ao criar uma nova sessao (POST /conversations). Essencial
   * quando a api-key do consumer so autoriza agentes especificos — sem isto, o
   * servidor usa seu default (`system.main`) e retorna 403. Omitir e seguro
   * apenas se `sessionId` ja esta definido e o Chat nunca precisar criar.
   */
  agentId?: string;
  initialMessages?: Message[];
  sessionOptions?: Record<string, unknown>;
  turnOptions?: Record<string, unknown>;
  placeholder?: string;
  footer?: React.ReactNode;
  className?: string;
  enableAttachments?: boolean;
  enableVoice?: boolean;
  /** Mostra combo de selecao de modelo (carregado via GET /models). */
  enableModelSelect?: boolean;
  /** Mostra seletor de locale no bottomSlot do input. Default: true. */
  enableLocaleSelect?: boolean;
  /** Mostra rodape de metadados do turno (duracao, custo, tokens, modelo). Default: true. */
  enableTurnMeta?: boolean;
  /**
   * Mostra o indicador "..." (3 reticências animadas) enquanto a resposta
   * ainda não chegou. Default: true. Desligar quando o consumer estiver
   * usando comfort messages (`status-toast`) emitidas pelo servidor —
   * a pill já cumpre o papel de feedback de carga.
   */
  enableStreamingIndicator?: boolean;
  /** Locale inicial (aceita "pt-BR", "pt_br", "pt", etc). Default: "en-US". */
  locale?: string;
  /** Callback quando o usuario troca o locale via selector. */
  onLocaleChange?: (locale: string) => void;
  /** Translation overrides keyed by locale slug. */
  messages?: CustomMessages;
  /** Metadata for custom locales (shown in locale selector). */
  locales?: CustomLocaleInfo;
  fetcher?: typeof fetch;
  /**
   * Transport opcional — usado pra carregar historico via getMessages quando
   * o consumer nao fornece initialMessages. Sem isto, o hook deriva do
   * `endpoint`. Util pra reusar o mesmo transport entre `<Chat>` e `<History>`.
   */
  transport?: ChatTransport;
  /**
   * Quando true (default), `<Chat>` busca o historico automaticamente ao
   * receber/trocar `sessionId`. Desligar quando o consumer passa
   * `initialMessages` ou gerencia o historico fora.
   */
  autoLoadHistory?: boolean;
  /**
   * Habilita a UI de form interativo pra tool nativa AskUserQuestion.
   * Quando true, o Chat:
   * - Adiciona `clientCapabilities.askUserQuestion: true` ao body do
   *   POST /conversations (servidor decide se respeita)
   * - Renderiza o form do part `ask-user-question`
   *
   * Default: false. Ligue só em apps onde o usuário deve poder responder
   * perguntas estruturadas do agente. Apps de chat unidirecional (notificações,
   * onboarding sem interação) deixam desligado.
   */
  enableAskUserQuestion?: boolean;
  /**
   * Artifacts — habilita parsing de tags `<antArtifact>` no texto do agente
   * e rendering em cards dedicados (code, markdown, html, svg, mermaid,
   * react). Declara `clientCapabilities.artifacts: true` no POST /conversations.
   * Default: false.
   */
  enableArtifacts?: boolean;
  emptyState?: React.ReactNode;
  /**
   * Max-width do conteudo do chat (mensagens + input). O chat se centraliza
   * horizontalmente dentro de um wrapper interno com esse limite. Passar
   * `false` desativa o limite e o chat ocupa 100% da largura disponivel.
   * Default: "3xl".
   */
  maxWidth?: ChatMaxWidth;
}

interface ChatContentProps {
  placeholder?: string;
  enableAttachments?: boolean;
  enableVoice?: boolean;
  enableTurnMeta?: boolean;
  enableStreamingIndicator?: boolean;
  emptyState?: React.ReactNode;
  bottomSlot?: React.ReactNode;
}

function NoSessionState({ children }: { children?: React.ReactNode }) {
  const { t } = useTranslation();
  return children ? (
    <>{children}</>
  ) : (
    <div className="flex h-full flex-col items-center justify-center gap-4 px-6 py-16 text-center">
      <div className="flex size-14 items-center justify-center rounded-2xl bg-primary/10 text-primary ring-1 ring-primary/20">
        <MessageSquare className="size-7" />
      </div>
      <div className="space-y-1.5">
        <h2 className="text-xl font-semibold tracking-tight">{t("chat.selectConversation")}</h2>
        <p className="max-w-sm text-sm text-muted-foreground">
          {t("chat.orCreateNew")}
        </p>
      </div>
    </div>
  );
}

function ChatContent({ placeholder, enableAttachments = true, enableVoice = true, enableTurnMeta = true, enableStreamingIndicator = true, emptyState, bottomSlot }: ChatContentProps) {
  const { messages, input, setInput, handleSubmit, isLoading, stop, error, reload } = useChatContext();

  return (
    <>
      <MessageList
        messages={messages}
        isLoading={isLoading}
        error={error ?? undefined}
        onRetry={reload}
        emptyState={emptyState}
        enableTurnMeta={enableTurnMeta}
        enableStreamingIndicator={enableStreamingIndicator}
      />
      <div className="px-4 pb-4">
        <MessageInput
          input={input}
          setInput={setInput}
          handleSubmit={handleSubmit}
          isLoading={isLoading}
          stop={stop}
          placeholder={placeholder}
          enableAttachments={enableAttachments}
          enableVoice={enableVoice}
          bottomSlot={bottomSlot}
        />
      </div>
    </>
  );
}

export function Chat({
  endpoint,
  token,
  sessionId,
  agentId,
  initialMessages,
  sessionOptions,
  turnOptions,
  placeholder,
  footer,
  className,
  enableAttachments,
  enableVoice,
  enableModelSelect,
  enableLocaleSelect = true,
  enableTurnMeta = true,
  enableStreamingIndicator = true,
  locale: localeProp,
  onLocaleChange,
  messages: messagesProp,
  locales: localesProp,
  fetcher,
  transport,
  autoLoadHistory = true,
  enableAskUserQuestion = false,
  enableArtifacts = false,
  emptyState,
  maxWidth = "3xl",
}: ChatProps) {
  const { models, defaultModel, isLoading: modelsLoading } = useModels(
    enableModelSelect ? endpoint : "",
    enableModelSelect ? fetcher : undefined,
  );
  const [selectedModel, setSelectedModel] = useState<string | undefined>(undefined);
  const resolvedLocale = useMemo(() => resolveLocale(localeProp), [localeProp]);
  const [currentLocale, setCurrentLocale] = useState(resolvedLocale);

  // Sync internal state when parent changes locale prop (e.g. via ChatHeader)
  useEffect(() => {
    setCurrentLocale(resolvedLocale);
  }, [resolvedLocale]);

  const handleLocaleChange = (l: string) => {
    setCurrentLocale(l);
    onLocaleChange?.(l);
  };

  // Resolve o modelo efetivo: selecionado pelo usuario ou default do catalogo
  const effectiveModel = enableModelSelect
    ? selectedModel ?? defaultModel ?? undefined
    : undefined;

  // Memoiza sessionOptions para evitar re-render infinito quando model muda
  const mergedSessionOptions = useMemo(
    () => sessionOptions,
    [sessionOptions],
  );

  const outerClass = cn(
    "flex flex-col flex-1 min-h-0 h-full bg-background text-foreground",
    maxWidth !== false && "items-center",
    className,
  );
  const innerClass = cn(
    "flex flex-col flex-1 min-h-0 w-full",
    maxWidth !== false && MAX_WIDTH_CLASS[maxWidth],
  );

  const hasBottomSlotContent = enableLocaleSelect || enableModelSelect;
  const bottomSlot = hasBottomSlotContent ? (
    <div className="flex items-center gap-1">
      {enableLocaleSelect && (
        <LocaleSelect value={currentLocale} onChange={handleLocaleChange} />
      )}
      {enableModelSelect && (
        <ModelSelect
          models={models}
          value={selectedModel ?? defaultModel ?? (models[0]?.id ?? "")}
          onChange={setSelectedModel}
          isLoading={modelsLoading}
        />
      )}
    </div>
  ) : undefined;

  if (!sessionId) {
    return (
      <LocaleProvider locale={currentLocale} messages={messagesProp} locales={localesProp}>
        <div className={outerClass}>
          <div className={innerClass}>
            <NoSessionState>{emptyState}</NoSessionState>
            {footer}
          </div>
        </div>
      </LocaleProvider>
    );
  }

  return (
    <LocaleProvider locale={currentLocale} messages={messagesProp} locales={localesProp}>
      <ChatProvider
        key={sessionId}
        endpoint={endpoint}
        token={token}
        sessionId={sessionId}
        agentId={agentId}
        initialMessages={initialMessages}
        sessionOptions={mergedSessionOptions}
        turnOptions={turnOptions}
        model={effectiveModel}
        fetcher={fetcher}
        transport={transport}
        autoLoadHistory={autoLoadHistory}
        clientCapabilities={enableAskUserQuestion ? { askUserQuestion: true } : undefined}
        enableArtifacts={enableArtifacts}
      >
        <div className={outerClass}>
          <div className={innerClass}>
            <ChatContent
              placeholder={placeholder}
              enableAttachments={enableAttachments}
              enableVoice={enableVoice}
              enableTurnMeta={enableTurnMeta}
              enableStreamingIndicator={enableStreamingIndicator}
              emptyState={emptyState}
              bottomSlot={bottomSlot}
            />
            {footer}
          </div>
        </div>
      </ChatProvider>
    </LocaleProvider>
  );
}

